{
 "level": "A1–B1",
 "intro": "In this topic you will learn how to form <strong>plural nouns</strong> in English, recognize <strong>exceptions</strong>, and distinguish nouns that exist only in the singular or only in the plural.",
 "rules": [
 {
 "label": "+ S",
 "color": "emerald",
 "text": "<strong>Most nouns</strong> form the plural by adding <strong>-s</strong>.",
 "example": "cat → cats, pen → pens, car → cars"
 },
 {
 "label": "+ ES",
 "color": "blue",
 "text": "We add <strong>-es</strong> after <strong>s, ss, x, z, ch, sh</strong> and often after <strong>consonant + o</strong>.",
 "example": "bus → buses, box → boxes, tomato → tomatoes"
 },
 {
 "label": "Y → IES",
 "color": "amber",
 "text": "After <strong>consonant + y</strong>, we change <strong>y → ies</strong>.",
 "example": "baby → babies, country → countries"
 },
 {
 "label": "F → VES",
 "color": "rose",
 "text": "Some nouns ending in <strong>-f / -fe</strong> change to <strong>-ves</strong>.",
 "example": "knife → knives, wolf → wolves"
 },
 {
 "label": "IRREGULAR",
 "color": "purple",
 "text": "Some nouns have <strong>irregular forms</strong> or do not change at all.",
 "example": "man → men, child → children, sheep → sheep"
 }
 ]
}

{
 "title": "1. Main ways to form the plural",
 "intro": "In most cases, it is enough to know four basic patterns:",
 "items": [
 {
 "label": "+ S",
 "title": "Just add -s",
 "subtitle": "chair → chairs, notebook → notebooks, apple → apples"
 },
 {
 "label": "+ ES",
 "title": "Add -es",
 "subtitle": "bus → buses, watch → watches, fox → foxes"
 },
 {
 "label": "Y → IES",
 "title": "Change y to ies",
 "subtitle": "lady → ladies, puppy → puppies, city → cities"
 },
 {
 "label": "F/FE → VES",
 "title": "Change f / fe to ves",
 "subtitle": "wife → wives, leaf → leaves, knife → knives"
 }
 ]
}

{
 "title": "2. Rule 1: add -s",
 "sections": [
 {
 "label": "Basic rule",
 "color": "emerald",
 "description": "Most countable nouns form the plural by simply <strong>adding -s</strong>.",
 "examples": [
 {
 "en": "cat → cats",
 "ua": "cat → cats"
 },
 {
 "en": "pen → pens",
 "ua": "pen → pens"
 },
 {
 "en": "car → cars",
 "ua": "car → cars"
 },
 {
 "en": "chair → chairs",
 "ua": "chair → chairs"
 }
 ]
 },
 {
 "label": "Regular endings",
 "color": "sky",
 "description": "If the noun ends in a vowel or in a regular consonant without a special spelling rule, we also just add <strong>-s</strong>.",
 "examples": [
 {
 "en": "toy → toys",
 "ua": "toy → toys"
 },
 {
 "en": "day → days",
 "ua": "day → days"
 },
 {
 "en": "radio → radios",
 "ua": "radio → radios"
 },
 {
 "en": "kangaroo → kangaroos",
 "ua": "kangaroo → kangaroos"
 }
 ]
 },
 {
 "label": "Agreement in a sentence",
 "color": "amber",
 "description": "In the plural, the noun changes, while the main verb usually stays in the base form. An important exception is <strong>to be → are</strong>.",
 "examples": [
 {
 "en": "Cats sleep a lot.",
 "ua": "Cats sleep a lot."
 },
 {
 "en": "My friends live in Lviv.",
 "ua": "My friends live in Lviv."
 },
 {
 "en": "The books are on the table.",
 "ua": "The books are on the table."
 }
 ],
 "note": "📌 Do not add -s to the verb after a plural subject: <strong>The cats run</strong>, not <strong>The cats runs</strong>."
 }
 ]
}

{
 "title": "3. Rule 2: when to add -es",
 "sections": [
 {
 "label": "After s, ss, x, z, ch, sh",
 "color": "blue",
 "description": "After hissing and whistling endings, we add <strong>-es</strong> so the word is easier to pronounce.",
 "examples": [
 {
 "en": "bus → buses",
 "ua": "bus → buses"
 },
 {
 "en": "kiss → kisses",
 "ua": "kiss → kisses"
 },
 {
 "en": "box → boxes",
 "ua": "box → boxes"
 },
 {
 "en": "church → churches",
 "ua": "church → churches"
 },
 {
 "en": "dish → dishes",
 "ua": "dish → dishes"
 }
 ]
 },
 {
 "label": "Consonant + o",
 "color": "purple",
 "description": "We often add <strong>-es</strong> after <strong>consonant + o</strong> as well.",
 "examples": [
 {
 "en": "tomato → tomatoes",
 "ua": "tomato → tomatoes"
 },
 {
 "en": "potato → potatoes",
 "ua": "potato → potatoes"
 },
 {
 "en": "hero → heroes",
 "ua": "hero → heroes"
 },
 {
 "en": "mosquito → mosquitoes",
 "ua": "mosquito → mosquitoes"
 }
 ]
 },
 {
 "label": "Exceptions in -o",
 "color": "sky",
 "description": "There are nouns ending in <strong>-o</strong> that still form the plural with <strong>-s</strong>.",
 "examples": [
 {
 "en": "photo → photos",
 "ua": "photo → photos"
 },
 {
 "en": "piano → pianos",
 "ua": "piano → pianos"
 },
 {
 "en": "radio → radios",
 "ua": "radio → radios"
 },
 {
 "en": "video → videos",
 "ua": "video → videos"
 }
 ],
 "note": "⚠️ For nouns ending in -o, check a dictionary if you are unsure."
 }
 ]
}

{
 "title": "4. Rule 3: when y becomes ies",
 "sections": [
 {
 "label": "Consonant + y",
 "color": "amber",
 "description": "If <strong>y</strong> comes after a consonant, we change <strong>y → ies</strong>.",
 "examples": [
 {
 "en": "country → countries",
 "ua": "country → countries"
 },
 {
 "en": "lady → ladies",
 "ua": "lady → ladies"
 },
 {
 "en": "family → families",
 "ua": "family → families"
 },
 {
 "en": "dictionary → dictionaries",
 "ua": "dictionary → dictionaries"
 }
 ]
 },
 {
 "label": "Vowel + y",
 "color": "emerald",
 "description": "If <strong>y</strong> comes after a vowel, we simply add <strong>-s</strong>.",
 "examples": [
 {
 "en": "toy → toys",
 "ua": "toy → toys"
 },
 {
 "en": "boy → boys",
 "ua": "boy → boys"
 },
 {
 "en": "holiday → holidays",
 "ua": "holiday → holidays"
 },
 {
 "en": "monkey → monkeys",
 "ua": "monkey → monkeys"
 }
 ]
 },
 {
 "label": "How to avoid confusion",
 "color": "sky",
 "description": "Look only at the letter before <strong>y</strong>: consonant → <strong>ies</strong>, vowel → <strong>ys</strong>.",
 "examples": [
 {
 "en": "baby → babies",
 "ua": "baby → babies"
 },
 {
 "en": "day → days",
 "ua": "day → days"
 }
 ],
 "note": "📌 This works in most basic A1–A2 cases."
 }
 ]
}

{
 "title": "5. Rule 4: f / fe → ves",
 "sections": [
 {
 "label": "Typical change",
 "color": "rose",
 "description": "Many nouns ending in <strong>-f</strong> or <strong>-fe</strong> change to <strong>-ves</strong>.",
 "examples": [
 {
 "en": "wolf → wolves",
 "ua": "wolf → wolves"
 },
 {
 "en": "wife → wives",
 "ua": "wife → wives"
 },
 {
 "en": "knife → knives",
 "ua": "knife → knives"
 },
 {
 "en": "leaf → leaves",
 "ua": "leaf → leaves"
 }
 ]
 },
 {
 "label": "More examples",
 "color": "amber",
 "description": "This pattern is also common in other everyday words.",
 "examples": [
 {
 "en": "life → lives",
 "ua": "life → lives"
 },
 {
 "en": "thief → thieves",
 "ua": "thief → thieves"
 },
 {
 "en": "shelf → shelves",
 "ua": "shelf → shelves"
 },
 {
 "en": "half → halves",
 "ua": "half → halves"
 }
 ]
 },
 {
 "label": "Exceptions",
 "color": "sky",
 "description": "Not every noun ending in <strong>-f</strong> changes to <strong>-ves</strong>. Some simply add <strong>-s</strong>, and some have two forms.",
 "examples": [
 {
 "en": "roof → roofs",
 "ua": "roof → roofs"
 },
 {
 "en": "chief → chiefs",
 "ua": "chief → chiefs"
 },
 {
 "en": "belief → beliefs",
 "ua": "belief → beliefs"
 },
 {
 "en": "wharf → wharfs / wharves",
 "ua": "wharf → wharfs / wharves"
 }
 ],
 "note": "⚠️ These words are best memorized separately."
 }
 ]
}

{
 "title": "6. Irregular plural forms",
 "sections": [
 {
 "label": "Vowel change",
 "color": "purple",
 "description": "Some nouns form the plural by changing an internal vowel.",
 "examples": [
 {
 "en": "man → men",
 "ua": "man → men"
 },
 {
 "en": "woman → women",
 "ua": "woman → women"
 },
 {
 "en": "foot → feet",
 "ua": "foot → feet"
 },
 {
 "en": "tooth → teeth",
 "ua": "tooth → teeth"
 },
 {
 "en": "goose → geese",
 "ua": "goose → geese"
 },
 {
 "en": "mouse → mice",
 "ua": "mouse → mice"
 }
 ]
 },
 {
 "label": "Different word form",
 "color": "rose",
 "description": "In some nouns, the plural form looks completely different from the singular.",
 "examples": [
 {
 "en": "child → children",
 "ua": "child → children"
 },
 {
 "en": "person → people",
 "ua": "person → people"
 },
 {
 "en": "ox → oxen",
 "ua": "ox → oxen"
 },
 {
 "en": "louse → lice",
 "ua": "louse → lice"
 }
 ]
 },
 {
 "label": "Classical forms",
 "color": "amber",
 "description": "Some scientific or formal nouns keep Latin or Greek plural patterns.",
 "examples": [
 {
 "en": "phenomenon → phenomena",
 "ua": "phenomenon → phenomena"
 },
 {
 "en": "criterion → criteria",
 "ua": "criterion → criteria"
 },
 {
 "en": "curriculum → curricula",
 "ua": "curriculum → curricula"
 }
 ]
 },
 {
 "label": "Same singular and plural",
 "color": "emerald",
 "description": "Some nouns have the same form in the singular and in the plural.",
 "examples": [
 {
 "en": "fish → fish",
 "ua": "fish → fish"
 },
 {
 "en": "sheep → sheep",
 "ua": "sheep → sheep"
 },
 {
 "en": "deer → deer",
 "ua": "deer → deer"
 },
 {
 "en": "aircraft → aircraft",
 "ua": "aircraft → aircraft"
 },
 {
 "en": "species → species",
 "ua": "species → species"
 },
 {
 "en": "shrimp → shrimp",
 "ua": "shrimp → shrimp"
 }
 ],
 "note": "📌 In special meanings you may sometimes see other forms, but for the basic level this rule is enough."
 }
 ]
}

{
 "title": "7. Quick table of rules",
 "intro": "A short comparison of the most important plural patterns:",
 "rows": [
 {
 "en": "Most nouns",
 "ua": "Most nouns",
 "note": "+ s: cat → cats, pen → pens"
 },
 {
 "en": "After s, ss, x, z, ch, sh",
 "ua": "After s, ss, x, z, ch, sh",
 "note": "+ es: box → boxes, church → churches"
 },
 {
 "en": "Consonant + y",
 "ua": "Consonant + y",
 "note": "y → ies: country → countries"
 },
 {
 "en": "Vowel + y",
 "ua": "Vowel + y",
 "note": "+ s: toy → toys, boy → boys"
 },
 {
 "en": "Many nouns ending in -f / -fe",
 "ua": "Many nouns ending in -f / -fe",
 "note": "f / fe → ves: knife → knives"
 },
 {
 "en": "Consonant + o",
 "ua": "Consonant + o",
 "note": "often + es: hero → heroes, potato → potatoes"
 },
 {
 "en": "Irregular plurals",
 "ua": "Irregular plurals",
 "note": "man → men, child → children, mouse → mice"
 },
 {
 "en": "Same singular and plural",
 "ua": "Same singular and plural",
 "note": "sheep → sheep, deer → deer"
 }
 ],
 "warning": "📌 If a noun looks unusual, check a dictionary: learners make the most mistakes with exceptions."
}

{
 "title": "8. Nouns used only in the singular",
 "sections": [
 {
 "label": "Uncountable nouns",
 "color": "indigo",
 "description": "Uncountable nouns usually <strong>do not have a plural form</strong> and take a singular verb.",
 "examples": [
 {
 "en": "water, milk, gold",
 "ua": "water, milk, gold"
 },
 {
 "en": "advice, information, happiness, wisdom",
 "ua": "advice, information, happiness, wisdom"
 },
 {
 "en": "weather, rain, snow",
 "ua": "weather, rain, snow"
 },
 {
 "en": "coffee, juice, meat",
 "ua": "coffee, juice, meat"
 }
 ]
 },
 {
 "label": "Sciences, languages, sports",
 "color": "sky",
 "description": "These words may look plural, but grammatically they often behave like singular nouns.",
 "examples": [
 {
 "en": "physics, mathematics, history",
 "ua": "physics, mathematics, history"
 },
 {
 "en": "English, Ukrainian, Chinese",
 "ua": "English, Ukrainian, Chinese"
 },
 {
 "en": "aerobics, athletics",
 "ua": "aerobics, athletics"
 }
 ]
 },
 {
 "label": "Typical sentences",
 "color": "emerald",
 "description": "With these nouns, we do not normally say <strong>informations</strong> or <strong>advices</strong> in the basic meaning.",
 "examples": [
 {
 "en": "The information is useful.",
 "ua": "The information is useful."
 },
 {
 "en": "Her advice was helpful.",
 "ua": "Her advice was helpful."
 },
 {
 "en": "The weather is cold today.",
 "ua": "The weather is cold today."
 }
 ],
 "note": "📌 In special contexts some of these nouns may have plural forms, but for standard rules treat them as singular-only."
 }
 ]
}

{
 "title": "9. Nouns used only in the plural",
 "sections": [
 {
 "label": "Paired objects",
 "color": "teal",
 "description": "Some objects made of two parts are used only in the plural. We often use them with <strong>a pair of</strong>.",
 "examples": [
 {
 "en": "trousers",
 "ua": "trousers"
 },
 {
 "en": "jeans",
 "ua": "jeans"
 },
 {
 "en": "glasses",
 "ua": "glasses"
 },
 {
 "en": "scissors",
 "ua": "scissors"
 },
 {
 "en": "binoculars",
 "ua": "binoculars"
 },
 {
 "en": "headphones",
 "ua": "headphones"
 }
 ]
 },
 {
 "label": "Other plural-only nouns",
 "color": "purple",
 "description": "Some nouns name collections, results, or fixed concepts and are also used only in the plural.",
 "examples": [
 {
 "en": "savings, earnings, goods",
 "ua": "savings, earnings, goods"
 },
 {
 "en": "archives, belongings",
 "ua": "archives, belongings"
 },
 {
 "en": "outskirts, surroundings, tropics",
 "ua": "outskirts, surroundings, tropics"
 },
 {
 "en": "congratulations, customs",
 "ua": "congratulations, customs"
 }
 ]
 },
 {
 "label": "Meaning changes",
 "color": "amber",
 "description": "Sometimes the singular form exists, but it means a different word or a different idea.",
 "examples": [
 {
 "en": "glasses = eyewear, glass = material / drinking glass",
 "ua": "glasses = eyewear, glass = material / drinking glass"
 },
 {
 "en": "customs = border control / traditions, custom = habit",
 "ua": "customs = border control / traditions, custom = habit"
 },
 {
 "en": "trousers are new / a pair of trousers",
 "ua": "trousers are new / a pair of trousers"
 }
 ],
 "note": "📌 We say <strong>These scissors are sharp</strong> and <strong>a pair of scissors</strong>."
 }
 ]
}

{
 "title": "10. Common mistakes",
 "items": [
 {
 "label": "Mistake 1",
 "color": "rose",
 "title": "Writing -s instead of -es after hissing sounds.",
 "wrong": "boxs, churchs, buss",
 "right": "✅ <span class=\"font-mono\">boxes, churches, buses</span>"
 },
 {
 "label": "Mistake 2",
 "color": "amber",
 "title": "Changing y after a vowel.",
 "wrong": "toies, boies, monkeies",
 "right": "✅ <span class=\"font-mono\">toys, boys, monkeys</span>"
 },
 {
 "label": "Mistake 3",
 "color": "purple",
 "title": "Using a regular plural where the form is irregular.",
 "wrong": "childs, mans, mouses",
 "right": "✅ <span class=\"font-mono\">children, men, mice</span>"
 },
 {
 "label": "Mistake 4",
 "color": "sky",
 "title": "Making uncountable nouns plural in their basic meaning.",
 "wrong": "informations, advices",
 "right": "✅ <span class=\"font-mono\">information, advice</span>"
 },
 {
 "label": "Mistake 5",
 "color": "teal",
 "title": "Using a singular article before a plural-only noun.",
 "wrong": "a scissor, a trousers",
 "right": "✅ <span class=\"font-mono\">scissors / a pair of scissors, trousers / a pair of trousers</span>"
 }
 ]
}

{
 "title": "12. Practice",
 "select_title": "Exercise 1. Choose the correct plural form",
 "select_intro": "Choose the correct option for each noun.",
 "selects": [
 {
 "label": "country → (countrys / countries / countrys)",
 "prompt": "Which form is correct?"
 },
 {
 "label": "potato → (potatos / potatoes / potatos)",
 "prompt": "Which form is correct?"
 },
 {
 "label": "photo → (photoes / photos / photies)",
 "prompt": "Which form is correct?"
 },
 {
 "label": "sheep → (sheeps / sheep / sheepen)",
 "prompt": "Which form is correct?"
 }
 ],
 "options": [
 "First option",
 "Second option",
 "Third option"
 ],
 "input_title": "Exercise 2. Write the plural form",
 "input_intro": "Write the correct plural form for these nouns.",
 "inputs": [
 {
 "before": "child → ",
 "after": ""
 },
 {
 "before": "knife → ",
 "after": ""
 },
 {
 "before": "mouse → ",
 "after": ""
 },
 {
 "before": "hero → ",
 "after": ""
 }
 ],
 "rephrase_title": "Exercise 3. Correct the mistakes",
 "rephrase_intro": "Find and correct the mistake in each sentence.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "I have two childs.",
 "example_target": "I have two children."
 },
 {
 "original": "1. There are three boxs on the table.",
 "placeholder": "Correct the mistake"
 },
 {
 "original": "2. She gave me useful informations.",
 "placeholder": "Correct the mistake"
 },
 {
 "original": "3. I bought a new scissor yesterday.",
 "placeholder": "Correct the mistake"
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "Plural Nouns — Plural Nouns",
 "current": true
 },
 {
 "label": "Countable vs Uncountable Nouns — Countable and uncountable nouns",
 "current": false
 },
 {
 "label": "Articles A / An / The — Articles",
 "current": false
 },
 {
 "label": "Some / Any / Much / Many — Quantity",
 "current": false
 }
 ]
}
